17	/******************************************************************************
18	 * Public Constructors
19	 ******************************************************************************/
20	
21	/**************************************************
22	 * Public Accessors : Aggregates
23	 *************************************************/
24	/* Find all the modules */
25	ModuleManager::module_range ModuleManager::modules() const {
26	  return vtr::make_range(ids_.begin(), ids_.end());
27	}
28	
29	std::vector<ModuleId> ModuleManager::modules_by_usage(
30	  const ModuleManager::e_module_usage_type& usage) const {
31	  std::vector<ModuleId> module_list;
32	  for (ModuleId curr_module : ids_) {
33	    if (usages_[curr_module] == usage) {
34	      module_list.push_back(curr_module);
35	    }
36	  }
37	  return module_list;
38	}
39	
40	/* Find all the ports belonging to a module */
41	ModuleManager::module_port_range ModuleManager::module_ports(
42	  const ModuleId& module) const {
43	  /* Validate the module_id */
44	  VTR_ASSERT(valid_module_id(module));
45	  return vtr::make_range(port_ids_[module].begin(), port_ids_[module].end());
46	}
47	
48	/* Find all the nets belonging to a module */
49	ModuleManager::module_net_range ModuleManager::module_nets(
50	  const ModuleId& module) const {
51	  /* Validate the module_id */
52	  VTR_ASSERT(valid_module_id(module));
53	  return vtr::make_range(
54	    module_net_iterator(ModuleNetId(0), invalid_net_ids_[module]),
55	    module_net_iterator(ModuleNetId(num_nets_[module]),
56	                        invalid_net_ids_[module]));
57	}
58	
59	/* Find all the child modules under a parent module */
60	std::vector<ModuleId> ModuleManager::child_modules(
61	  const ModuleId& parent_module) const {
62	  /* Validate the module_id */
63	  VTR_ASSERT(valid_module_id(parent_module));
64	  return children_[parent_module];
65	}
66	
67	/* Find all the instances under a parent module */
68	std::vector<size_t> ModuleManager::child_module_instances(
69	  const ModuleId& parent_module, const ModuleId& child_module) const {
70	  /* Validate the module_id */
71	  VTR_ASSERT(valid_module_id(parent_module));
72	  /* Ensure that the child module is in the child list of parent module */
73	  size_t child_index = children_[parent_module].size();
74	  for (size_t i = 0; i < children_[parent_module].size(); ++i) {
75	    if (child_module == children_[parent_module][i]) {
76	      child_index = i;
77	      break;
78	    }
79	  }
80	  VTR_ASSERT(child_index != children_[parent_module].size());
81	
82	  /* Create a vector, with sequentially increasing numbers */
83	  std::vector<size_t> instance_range(
84	    num_child_instances_[parent_module][child_index], 0);
85	  std::iota(instance_range.begin(), instance_range.end(), 0);
86	
87	  return instance_range;
88	}
89	
90	/* Find all the configurable child modules under a parent module */
91	std::vector<ModuleId> ModuleManager::configurable_children(
92	  const ModuleId& parent_module, const e_config_child_type& type) const {
93	  /* Validate the module_id */
94	  VTR_ASSERT(valid_module_id(parent_module));
95	
96	  if (type == ModuleManager::e_config_child_type::LOGICAL) {
97	    return logical_configurable_children_[parent_module];
98	  }
99	  VTR_ASSERT(type == ModuleManager::e_config_child_type::PHYSICAL);
100	  return physical_configurable_children_[parent_module];
101	}
102	
103	/* Find all the instances of configurable child modules under a parent module */
104	std::vector<size_t> ModuleManager::configurable_child_instances(
105	  const ModuleId& parent_module, const e_config_child_type& type) const {
106	  /* Validate the module_id */
107	  VTR_ASSERT(valid_module_id(parent_module));
108	
109	  if (type == ModuleManager::e_config_child_type::LOGICAL) {
110	    return logical_configurable_child_instances_[parent_module];
111	  }
112	  VTR_ASSERT(type == ModuleManager::e_config_child_type::PHYSICAL);
113	  return physical_configurable_child_instances_[parent_module];
114	}
115	
116	std::vector<vtr::Point<int>> ModuleManager::configurable_child_coordinates(
117	  const ModuleId& parent_module, const e_config_child_type& type) const {
118	  /* Validate the module_id */
119	  VTR_ASSERT(valid_module_id(parent_module));
120	  VTR_ASSERT(type == ModuleManager::e_config_child_type::PHYSICAL);
121	
122	  return physical_configurable_child_coordinates_[parent_module];
123	}
124	
125	/* Find all the configurable child modules under a parent module */
126	std::vector<ModuleId> ModuleManager::logical2physical_configurable_children(
127	  const ModuleId& parent_module) const {
128	  /* Validate the module_id */
129	  VTR_ASSERT(valid_module_id(parent_module));
130	
131	  return logical2physical_configurable_children_[parent_module];
132	}
133	
134	/* Find all the instances of configurable child modules under a parent module */
135	std::vector<std::string>
136	ModuleManager::logical2physical_configurable_child_instance_names(
137	  const ModuleId& parent_module) const {
138	  /* Validate the module_id */
139	  VTR_ASSERT(valid_module_id(parent_module));
140	
141	  return logical2physical_configurable_child_instance_names_[parent_module];
142	}
143	
144	/* Find all the configurable child modules under a parent module */
145	std::vector<ModuleId> ModuleManager::io_children(
146	  const ModuleId& parent_module) const {
147	  /* Validate the module_id */
148	  VTR_ASSERT(valid_module_id(parent_module));
149	
150	  return io_children_[parent_module];
151	}
152	
153	/* Find all the instances of configurable child modules under a parent module */
154	std::vector<size_t> ModuleManager::io_child_instances(
155	  const ModuleId& parent_module) const {
156	  /* Validate the module_id */
157	  VTR_ASSERT(valid_module_id(parent_module));
158	
159	  return io_child_instances_[parent_module];
160	}
161	
162	std::vector<vtr::Point<int>> ModuleManager::io_child_coordinates(
163	  const ModuleId& parent_module) const {
