169	
170	/* Find the source ids of modules */
171	ModuleManager::module_net_src_range ModuleManager::module_net_sources(
172	  const ModuleId& module, const ModuleNetId& net) const {
173	  /* Validate the module_id */
174	  VTR_ASSERT(valid_module_net_id(module, net));
175	  return vtr::make_range(net_src_ids_[module][net].begin(),
176	                         net_src_ids_[module][net].end());
177	}
178	
179	/* Find the sink ids of modules */
180	ModuleManager::module_net_sink_range ModuleManager::module_net_sinks(
181	  const ModuleId& module, const ModuleNetId& net) const {
182	  /* Validate the module_id */
183	  VTR_ASSERT(valid_module_net_id(module, net));
184	  return vtr::make_range(net_sink_ids_[module][net].begin(),
185	                         net_sink_ids_[module][net].end());
186	}
187	
188	ModuleManager::region_range ModuleManager::regions(
189	  const ModuleId& module) const {
190	  VTR_ASSERT(valid_module_id(module));
191	  return vtr::make_range(config_region_ids_[module].begin(),
192	                         config_region_ids_[module].end());
193	}
194	
195	std::vector<ModuleId> ModuleManager::region_configurable_children(
196	  const ModuleId& parent_module, const ConfigRegionId& region) const {
197	  /* Validate the module_id */
198	  VTR_ASSERT(valid_module_id(parent_module));
199	  VTR_ASSERT(valid_region_id(parent_module, region));
200	
201	  std::vector<ModuleId> region_config_children;
202	  region_config_children.reserve(
203	    config_region_children_[parent_module][region].size());
204	
205	  for (const size_t& child_id :
206	       config_region_children_[parent_module][region]) {
207	    region_config_children.push_back(
208	      physical_configurable_children_[parent_module][child_id]);
209	  }
210	
211	  return region_config_children;
212	}
213	
214	std::vector<size_t> ModuleManager::region_configurable_child_instances(
215	  const ModuleId& parent_module, const ConfigRegionId& region) const {
216	  /* Validate the module_id */
217	  VTR_ASSERT(valid_module_id(parent_module));
218	  VTR_ASSERT(valid_region_id(parent_module, region));
219	
220	  std::vector<size_t> region_config_child_instances;
221	  region_config_child_instances.reserve(
222	    config_region_children_[parent_module][region].size());
223	
224	  for (const size_t& child_id :
225	       config_region_children_[parent_module][region]) {
226	    region_config_child_instances.push_back(
227	      physical_configurable_child_instances_[parent_module][child_id]);
228	  }
229	
230	  return region_config_child_instances;
231	}
232	
233	std::vector<vtr::Point<int>>
234	ModuleManager::region_configurable_child_coordinates(
235	  const ModuleId& parent_module, const ConfigRegionId& region) const {
236	  /* Validate the module_id */
237	  VTR_ASSERT(valid_module_id(parent_module));
238	  VTR_ASSERT(valid_region_id(parent_module, region));
239	
240	  std::vector<vtr::Point<int>> region_config_child_coordinates;
241	  region_config_child_coordinates.reserve(
242	    config_region_children_[parent_module][region].size());
243	
244	  for (const size_t& child_id :
245	       config_region_children_[parent_module][region]) {
246	    region_config_child_coordinates.push_back(
247	      physical_configurable_child_coordinates_[parent_module][child_id]);
248	  }
249	
250	  return region_config_child_coordinates;
251	}
252	
253	/******************************************************************************
254	 * Public Accessors
255	 ******************************************************************************/
256	/* Return number of modules */
257	size_t ModuleManager::num_modules() const { return ids_.size(); }
258	
259	/* Return number of net of a module */
260	size_t ModuleManager::num_nets(const ModuleId& module) const {
261	  /* Validate the module_id */
262	  VTR_ASSERT(valid_module_id(module));
263	  return num_nets_[module];
264	}
265	
266	/* Find the name of a module */
267	std::string ModuleManager::module_name(const ModuleId& module_id) const {
268	  /* Validate the module_id */
269	  VTR_ASSERT(valid_module_id(module_id));
270	  return names_[module_id];
271	}
272	
273	ModuleManager::e_module_usage_type ModuleManager::module_usage(
274	  const ModuleId& module_id) const {
275	  /* Validate the module_id */
276	  VTR_ASSERT(valid_module_id(module_id));
277	  return usages_[module_id];
278	}
279	
280	/* Get the string of a module port type */
281	std::string ModuleManager::module_port_type_str(
282	  const enum e_module_port_type& port_type) const {
283	  std::array<const char*, NUM_MODULE_PORT_TYPES> MODULE_PORT_TYPE_STRING = {
284	    {"GLOBAL PORTS", "GPIN PORTS", "GPOUT PORTS", "GPIO PORTS", "INOUT PORTS",
285	     "INPUT PORTS", "OUTPUT PORTS", "CLOCK PORTS"}};
286	  return MODULE_PORT_TYPE_STRING[port_type];
287	}
288	
289	/* Find a list of ports of a module by a given types */
290	std::vector<BasicPort> ModuleManager::module_ports_by_type(
291	  const ModuleId& module_id, const enum e_module_port_type& port_type) const {
292	  /* Validate the module_id */
293	  VTR_ASSERT(valid_module_id(module_id));
294	
295	  std::vector<BasicPort> ports;
296	  for (const auto& port : port_ids_[module_id]) {
297	    /* Skip unmatched ports */
298	    if (port_type != port_types_[module_id][port]) {
299	      continue;
300	    }
301	    ports.push_back(ports_[module_id][port]);
302	  }
303	
304	  return ports;
305	}
306	
307	e_side ModuleManager::port_side(const ModuleId& module_id,
308	                                const ModulePortId& port_id) const {
309	  VTR_ASSERT(valid_module_port_id(module_id, port_id));
310	  return port_sides_[module_id][port_id];
311	}
312	
313	/* Find a list of port ids of a module by a given types */
314	std::vector<ModulePortId> ModuleManager::module_port_ids_by_type(
315	  const ModuleId& module_id, const enum e_module_port_type& port_type) const {
316	  /* Validate the module_id */
317	  VTR_ASSERT(valid_module_id(module_id));
318	
319	  std::vector<ModulePortId> port_ids;
320	  for (const auto& port : port_ids_[module_id]) {
321	    /* Skip unmatched ports */
322	    if (port_type != port_types_[module_id][port]) {
323	      continue;
324	    }
325	    port_ids.push_back(port_ids_[module_id][port]);
326	  }
327	
328	  return port_ids;
329	}
330	
331	/* Find a port of a module by a given name */
332	ModulePortId ModuleManager::find_module_port(
333	  const ModuleId& module_id, const std::string& port_name) const {
334	  /* Validate the module id */
335	  VTR_ASSERT(valid_module_id(module_id));
336	
337	  /* Iterate over the ports of the module */
338	  for (const auto& port : port_ids_[module_id]) {
339	    if (0 == port_name.compare(ports_[module_id][port].get_name())) {
340	      /* Find it, return the id */
341	      return port;
342	    }
343	  }
344	  /* Not found, return an invalid id */
345	  return ModulePortId::INVALID();
346	}
347	
348	/* Find the Port information with a given port id */
349	BasicPort ModuleManager::module_port(const ModuleId& module_id,
350	                                     const ModulePortId& port_id) const {
351	  /* Validate the module and port id */
352	  VTR_ASSERT(valid_module_port_id(module_id, port_id));
353	  return ports_[module_id][port_id];
354	}
355	
356	/* Find the module id by a given name, return invalid if not found */
357	ModuleId ModuleManager::find_module(const std::string& name) const {
