383	  /* Validate the id of both parent and child modules */
384	  VTR_ASSERT(valid_module_id(parent_module));
385	  VTR_ASSERT(valid_module_id(child_module));
386	
387	  /* Find the index of child module in the child list of parent module */
388	  size_t child_index =
389	    find_child_module_index_in_parent_module(parent_module, child_module);
390	  VTR_ASSERT(child_index < children_[parent_module].size());
391	  /* Ensure that instance id is valid */
