396	/* Find the instance id of a given instance name */
397	size_t ModuleManager::instance_id(const ModuleId& parent_module,
398	                                  const ModuleId& child_module,
399	                                  const std::string& instance_name) const {
400	  /* Validate the id of both parent and child modules */
401	  VTR_ASSERT(valid_module_id(parent_module));
402	  VTR_ASSERT(valid_module_id(child_module));
403	
404	  /* Find the index of child module in the child list of parent module */
405	  size_t child_index =
406	    find_child_module_index_in_parent_module(parent_module, child_module);
407	  VTR_ASSERT(child_index < children_[parent_module].size());
408	
409	  /* Search the instance name list and try to find a match */
410	  for (size_t name_id = 0;
411	       name_id < child_instance_names_[parent_module][child_index].size();
412	       ++name_id) {
413	    const std::string& name =
414	      child_instance_names_[parent_module][child_index][name_id];
415	    if (0 == name.compare(instance_name)) {
416	      return name_id;
417	    }
418	  }
419	
420	  /* Not found, return an invalid name */
421	  return size_t(-1);
422	}
