567	/* Identify if a pin of a port in a module already exists in the net source
568	 * list*/
569	bool ModuleManager::net_source_exist(const ModuleId& module,
570	                                     const ModuleNetId& net,
571	                                     const ModuleId& src_module,
572	                                     const size_t& instance_id,
573	                                     const ModulePortId& src_port,
574	                                     const size_t& src_pin) {
575	  /* Validate module net */
576	  VTR_ASSERT(valid_module_net_id(module, net));
577	
578	  /* Iterate over each source of the net.
579	   * If a net source has the same src_module, instance_id, src_port and src_pin,
580	   * we can say that the source has already been added to this net!
581	   */
582	  for (const ModuleNetSrcId& net_src : module_net_sources(module, net)) {
583	    if ((src_module ==
584	         net_terminal_storage_[net_src_terminal_ids_[module][net][net_src]]
585	           .first) &&
586	        (instance_id == net_source_instances(module, net)[net_src]) &&
587	        (src_port ==
588	         net_terminal_storage_[net_src_terminal_ids_[module][net][net_src]]
589	           .second) &&
590	        (src_pin == net_source_pins(module, net)[net_src])) {
591	      return true;
592	    }
593	  }
594	
595	  /* Reach here, it means nothing has been found. Return false */
596	  return false;
597	}
