678	bool ModuleManager::unified_configurable_children(
679	  const ModuleId& curr_module) const {
680	  if (logical_configurable_children_[curr_module].size() !=
681	      physical_configurable_children_[curr_module].size()) {
682	    return false;
683	  }
684	  for (size_t ichild = 0;
685	       ichild < logical_configurable_children_[curr_module].size(); ++ichild) {
686	    if (logical_configurable_children_[curr_module][ichild] !=
687	        physical_configurable_children_[curr_module][ichild]) {
688	      return false;
689	    }
690	    if (logical_configurable_child_instances_[curr_module][ichild] !=
691	        physical_configurable_child_instances_[curr_module][ichild]) {
692	      return false;
693	    }
694	  }
695	  return true;
696	}
