699	 * Private Accessors
700	 ******************************************************************************/
701	size_t ModuleManager::find_child_module_index_in_parent_module(
702	  const ModuleId& parent_module, const ModuleId& child_module) const {
703	  /* validate both module ids */
704	  VTR_ASSERT(valid_module_id(parent_module));
705	  VTR_ASSERT(valid_module_id(child_module));
706	  /* Try to find the child_module in the children list of parent_module*/
707	  for (size_t i = 0; i < children_[parent_module].size(); ++i) {
708	    if (child_module == children_[parent_module][i]) {
709	      /* Found, return the number of instances */
710	      return i;
711	    }
712	  }
713	  /* Not found: return an valid value */
714	  return size_t(-1);
715	}
