720	/* Add a module */
721	ModuleId ModuleManager::add_module(const std::string& name) {
722	  /* Find if the name has been used. If used, return an invalid Id and report
723	   * error! */
724	  std::map<std::string, ModuleId>::iterator it = name_id_map_.find(name);
725	  if (it != name_id_map_.end()) {
726	    return ModuleId::INVALID();
727	  }
728	
729	  /* Create an new id */
730	  ModuleId module = ModuleId(ids_.size());
731	  ids_.push_back(module);
732	
733	  /* Allocate other attributes */
734	  names_.push_back(name);
735	  usages_.push_back(NUM_MODULE_USAGE_TYPES);
736	  parents_.emplace_back();
737	  children_.emplace_back();
738	  num_child_instances_.emplace_back();
739	  child_instance_names_.emplace_back();
740	  logical_configurable_children_.emplace_back();
741	  logical_configurable_child_instances_.emplace_back();
742	  physical_configurable_children_.emplace_back();
743	  physical_configurable_child_instances_.emplace_back();
744	  physical_configurable_child_regions_.emplace_back();
745	  physical_configurable_child_coordinates_.emplace_back();
746	
747	  logical2physical_configurable_children_.emplace_back();
748	  logical2physical_configurable_child_instance_names_.emplace_back();
749	
750	  config_region_ids_.emplace_back();
751	  config_region_children_.emplace_back();
752	
753	  io_children_.emplace_back();
754	  io_child_instances_.emplace_back();
755	  io_child_coordinates_.emplace_back();
756	
757	  port_ids_.emplace_back();
758	  ports_.emplace_back();
759	  port_types_.emplace_back();
760	  port_is_wire_.emplace_back();
761	  port_default_val_.emplace_back();
762	  port_is_mappable_io_.emplace_back();
763	  port_is_register_.emplace_back();
764	  port_sides_.emplace_back();
765	  port_preproc_flags_.emplace_back();
766	
767	  num_nets_.emplace_back(0);
768	  invalid_net_ids_.emplace_back();
769	  net_names_.emplace_back();
770	  net_src_ids_.emplace_back();
771	  net_src_terminal_ids_.emplace_back();
772	  net_src_instance_ids_.emplace_back();
773	  net_src_pin_ids_.emplace_back();
774	
775	  net_sink_ids_.emplace_back();
776	  net_sink_terminal_ids_.emplace_back();
777	  net_sink_instance_ids_.emplace_back();
778	  net_sink_pin_ids_.emplace_back();
779	
780	  /* Register in the name-to-id map */
781	  name_id_map_[name] = module;
782	
783	  /* Build port lookup */
784	  port_lookup_.emplace_back();
785	  port_lookup_[module].resize(NUM_MODULE_PORT_TYPES);
786	
787	  /* Build fast look-up for nets */
788	  net_lookup_.emplace_back();
789	  /* Reserve the instance 0 for the module */
790	  net_lookup_[module][module].emplace_back();
791	
792	  /* Return the new id */
793	  return module;
794	}
