796	/* Add a port to a module */
797	ModulePortId ModuleManager::add_port(const ModuleId& module,
798	                                     const BasicPort& port_info,
799	                                     const enum e_module_port_type& port_type) {
800	  /* Validate the id of module */
801	  VTR_ASSERT(valid_module_id(module));
802	
803	  /* Add port and fill port attributes */
804	  ModulePortId port = ModulePortId(port_ids_[module].size());
805	  port_ids_[module].push_back(port);
806	  ports_[module].push_back(port_info);
807	  port_types_[module].push_back(port_type);
808	  /* Deposit invalid value for each side */
809	  port_sides_[module].push_back(NUM_2D_SIDES);
810	  port_is_wire_[module].push_back(false);
811	  port_is_mappable_io_[module].push_back(false);
812	  port_default_val_[module].push_back('0');
813	  port_is_register_[module].push_back(false);
814	  port_preproc_flags_[module]
815	    .emplace_back(); /* Create an empty string for the pre-processing flags */
816	
817	  /* Update fast look-up for port */
818	  port_lookup_[module][port_type].push_back(port);
819	
820	  /* Update fast look-up for nets */
821	  VTR_ASSERT_SAFE(1 == net_lookup_[module][module].size());
822	  net_lookup_[module][module][0][port].resize(port_info.get_width(),
823	                                              ModuleNetId::INVALID());
824	
825	  return port;
826	}
