933	/* Add a child module to a parent module */
934	void ModuleManager::add_child_module(const ModuleId& parent_module,
935	                                     const ModuleId& child_module,
936	                                     const bool& is_io_child) {
937	  /* Validate the id of both parent and child modules */
938	  VTR_ASSERT(valid_module_id(parent_module));
939	  VTR_ASSERT(valid_module_id(child_module));
940	
941	  /* Try to find if the parent module is already in the list */
942	  std::vector<ModuleId>::iterator parent_it =
943	    std::find(parents_[child_module].begin(), parents_[child_module].end(),
944	              parent_module);
945	  if (parent_it == parents_[child_module].end()) {
946	    /* Update the parent module of child module */
947	    parents_[child_module].push_back(parent_module);
948	  }
949	
950	  std::vector<ModuleId>::iterator child_it =
951	    std::find(children_[parent_module].begin(), children_[parent_module].end(),
952	              child_module);
953	  int child_instance_id = -1;
954	  if (child_it == children_[parent_module].end()) {
955	    /* Update the child module of parent module */
956	    children_[parent_module].push_back(child_module);
957	    num_child_instances_[parent_module].push_back(1); /* By default give one */
958	    child_instance_id = 0;
959	    /* Update the instance name list */
960	    child_instance_names_[parent_module].emplace_back();
961	    child_instance_names_[parent_module].back().emplace_back();
962	  } else {
963	    /* Increase the counter of instances */
964	    child_instance_id =
965	      num_child_instances_[parent_module]
966	                          [child_it - children_[parent_module].begin()];
967	    num_child_instances_[parent_module]
968	                        [child_it - children_[parent_module].begin()]++;
969	    child_instance_names_[parent_module]
970	                         [child_it - children_[parent_module].begin()]
971	                           .emplace_back();
972	  }
973	
974	  /* Add to I/O child if needed */
975	  if (is_io_child) {
976	    add_io_child(parent_module, child_module, child_instance_id);
977	  }
978	
979	  /* Update fast look-up for nets */
980	  size_t instance_id = net_lookup_[parent_module][child_module].size();
981	  net_lookup_[parent_module][child_module].emplace_back();
982	  /* Find the ports for the child module and update the fast look-up */
983	  for (ModulePortId child_port : port_ids_[child_module]) {
984	    net_lookup_[parent_module][child_module][instance_id][child_port].resize(
985	      ports_[child_module][child_port].get_width(), ModuleNetId::INVALID());
986	  }
987	}
