1079	void ModuleManager::reserve_configurable_child(
1080	  const ModuleId& parent_module, const size_t& num_children,
1081	  const e_config_child_type& type) {
1082	  VTR_ASSERT(valid_module_id(parent_module));
1083	  if (type == ModuleManager::e_config_child_type::LOGICAL ||
1084	      type == ModuleManager::e_config_child_type::UNIFIED) {
1085	    /* Do reserve when the number of children is larger than current size of
1086	     * lists
1087	     */
1088	    if (num_children > logical_configurable_children_[parent_module].size()) {
1089	      logical_configurable_children_[parent_module].reserve(num_children);
1090	    }
1091	    if (num_children >
1092	        logical_configurable_child_instances_[parent_module].size()) {
1093	      logical_configurable_child_instances_[parent_module].reserve(
1094	        num_children);
1095	    }
1096	    if (num_children >
1097	        logical2physical_configurable_children_[parent_module].size()) {
1098	      logical2physical_configurable_children_[parent_module].reserve(
1099	        num_children);
1100	    }
1101	    if (num_children >
1102	        logical2physical_configurable_child_instance_names_[parent_module]
1103	          .size()) {
1104	      logical2physical_configurable_child_instance_names_[parent_module]
1105	        .reserve(num_children);
1106	    }
1107	  }
1108	  if (type == ModuleManager::e_config_child_type::PHYSICAL ||
1109	      type == ModuleManager::e_config_child_type::UNIFIED) {
1110	    if (num_children > physical_configurable_children_[parent_module].size()) {
1111	      physical_configurable_children_[parent_module].reserve(num_children);
1112	    }
1113	    if (num_children >
1114	        physical_configurable_child_instances_[parent_module].size()) {
1115	      physical_configurable_child_instances_[parent_module].reserve(
1116	        num_children);
1117	    }
1118	    if (num_children >
1119	        physical_configurable_child_regions_[parent_module].size()) {
1120	      physical_configurable_child_regions_[parent_module].reserve(num_children);
1121	    }
1122	    if (num_children >
1123	        physical_configurable_child_coordinates_[parent_module].size()) {
1124	      physical_configurable_child_coordinates_[parent_module].reserve(
1125	        num_children);
1126	    }
1127	  }
1128	}
