1144	void ModuleManager::add_configurable_child_to_region(
1145	  const ModuleId& parent_module, const ConfigRegionId& config_region,
1146	  const ModuleId& child_module, const size_t& child_instance,
1147	  const size_t& config_child_id) {
1148	  /* Validate the module id */
1149	  VTR_ASSERT(valid_module_id(parent_module));
1150	  VTR_ASSERT(valid_module_id(child_module));
1151	  VTR_ASSERT(valid_region_id(parent_module, config_region));
1152	
1153	  /* Ensure that the child module is in the configurable children list */
1154	  VTR_ASSERT(child_module ==
1155	             configurable_children(
1156	               parent_module,
1157	               ModuleManager::e_config_child_type::PHYSICAL)[config_child_id]);
1158	  VTR_ASSERT(child_instance ==
1159	             configurable_child_instances(
1160	               parent_module,
1161	               ModuleManager::e_config_child_type::PHYSICAL)[config_child_id]);
1162	
1163	  /* If the child is already in another region, error out */
1164	  if ((true == valid_region_id(
1165	                 parent_module,
1166	                 physical_configurable_child_regions_[parent_module]
1167	                                                     [config_child_id])) &&
1168	      (config_region !=
1169	       physical_configurable_child_regions_[parent_module][config_child_id])) {
1170	    VTR_LOGF_ERROR(
1171	      __FILE__, __LINE__,
1172	      "Try to add a configurable child '%s[%lu]' to region '%lu' which is "
1173	      "already added to another region '%lu'!\n",
1174	      module_name(child_module).c_str(), child_instance, size_t(config_region),
1175	      size_t(
1176	        physical_configurable_child_regions_[parent_module][config_child_id]));
1177	    exit(1);
1178	  }
1179	
1180	  /* Passed all the checks, add the child to the region */
1181	  config_region_children_[parent_module][config_region].push_back(
1182	    config_child_id);
1183	}
