1284	/* Add a source to a net in the connection graph */
1285	ModuleNetSrcId ModuleManager::add_module_net_source(
1286	  const ModuleId& module, const ModuleNetId& net, const ModuleId& src_module,
1287	  const size_t& instance_id, const ModulePortId& src_port,
1288	  const size_t& src_pin) {
1289	  /* Validate the module and net id */
1290	  VTR_ASSERT(valid_module_net_id(module, net));
1291	
1292	  /* Create a new id for src node */
1293	  ModuleNetSrcId net_src = ModuleNetSrcId(net_src_ids_[module][net].size());
1294	  net_src_ids_[module][net].push_back(net_src);
1295	
1296	  /* Validate the source module */
1297	  VTR_ASSERT(valid_module_id(src_module));
1298	
1299	  /* Validate the port exists in the src module */
1300	  VTR_ASSERT(valid_module_port_id(src_module, src_port));
1301	
1302	  /* Create pair of module and port
1303	   * Search in the storage. If found, use the existing pair
1304	   * Otherwise, add the pair
1305	   */
1306	  std::pair<ModuleId, ModulePortId> terminal(src_module, src_port);
1307	  std::vector<std::pair<ModuleId, ModulePortId>>::iterator it = std::find(
1308	    net_terminal_storage_.begin(), net_terminal_storage_.end(), terminal);
1309	  if (it == net_terminal_storage_.end()) {
1310	    net_src_terminal_ids_[module][net].push_back(net_terminal_storage_.size());
1311	    net_terminal_storage_.push_back(terminal);
1312	  } else {
1313	    VTR_ASSERT_SAFE(it != net_terminal_storage_.end());
1314	    net_src_terminal_ids_[module][net].push_back(
1315	      std::distance(net_terminal_storage_.begin(), it));
1316	  }
1317	
1318	  /* if it has the same id as module, our instance id will be by default 0 */
1319	  size_t src_instance_id = instance_id;
1320	  if (src_module == module) {
1321	    src_instance_id = 0;
1322	    net_src_instance_ids_[module][net].push_back(src_instance_id);
1323	  } else {
1324	    /* Check the instance id of the src module */
1325	    VTR_ASSERT(src_instance_id < num_instance(module, src_module));
1326	    net_src_instance_ids_[module][net].push_back(src_instance_id);
1327	  }
1328	
1329	  /* Validate the pin id is in the range of the port width */
1330	  VTR_ASSERT(src_pin < module_port(src_module, src_port).get_width());
1331	  net_src_pin_ids_[module][net].push_back(src_pin);
1332	
1333	  /* Update fast look-up for nets */
1334	  net_lookup_[module][src_module][src_instance_id][src_port][src_pin] = net;
1335	
1336	  return net_src;
1337	}
