1406	ModuleId ModuleManager::create_wrapper_module(
1407	  const ModuleId& existing_module, const std::string& wrapper_module_name,
1408	  const std::string& instance_name, const bool& add_nets) {
1409	  /* Create a new module with the given name */
1410	  ModuleId wrapper_module = add_module(wrapper_module_name);
1411	  if (!wrapper_module) {
1412	    return wrapper_module;
1413	  }
1414	  /* Add the existing module as an instance */
1415	  add_child_module(wrapper_module, existing_module, false);
1416	  set_child_instance_name(wrapper_module, existing_module, 0, instance_name);
1417	
1418	  /* A fast-lookup on the port linking: wrapper_module port -> existing_module
1419	   * port */
1420	  std::map<ModulePortId, ModulePortId> port_map;
1421	  /* Herit ports */
1422	  for (ModulePortId existing_port : module_ports(existing_module)) {
1423	    /* Create new port */
1424	    BasicPort existing_port_info = module_port(existing_module, existing_port);
1425	    ModuleManager::e_module_port_type existing_port_type =
1426	      port_type(existing_module, existing_port);
1427	    ModulePortId new_port =
1428	      add_port(wrapper_module, existing_port_info, existing_port_type);
1429	    /* Set port attributes */
1430	    set_port_is_wire(wrapper_module, new_port,
1431	                     port_is_wire(existing_module, existing_port));
1432	    set_port_is_mappable_io(
1433	      wrapper_module, new_port,
1434	      port_is_mappable_io(existing_module, existing_port));
1435	    set_port_default_val(wrapper_module, new_port,
1436	                         port_default_val(existing_module, existing_port));
1437	    set_port_is_register(wrapper_module, new_port,
1438	                         port_is_register(existing_module, existing_port));
1439	    set_port_preproc_flag(wrapper_module, new_port,
1440	                          port_preproc_flag(existing_module, existing_port));
1441	    /* Register in port mapping */
1442	    port_map[new_port] = existing_port;
1443	  }
1444	
1445	  /* Add nets */
1446	  if (!add_nets) {
1447	    return wrapper_module;
1448	  }
1449	  /* The number of nets are the sum of input and output pins */
1450	  size_t num_nets_to_reserve = 0;
1451	  for (ModulePortId new_port : module_ports(wrapper_module)) {
1452	    BasicPort new_port_info = module_port(wrapper_module, new_port);
1453	    num_nets_to_reserve += new_port_info.get_width();
1454	  }
1455	  reserve_module_nets(wrapper_module, num_nets_to_reserve);
1456	  for (ModulePortId new_port : module_ports(wrapper_module)) {
1457	    BasicPort new_port_info = module_port(wrapper_module, new_port);
1458	    /* For each input pin, create a new source */
1459	    ModuleManager::e_module_port_type new_port_type =
1460	      port_type(wrapper_module, new_port);
1461	    /* Check if the pin size are matching or not */
1462	    ModulePortId existing_port = port_map[new_port];
1463	    BasicPort existing_port_info = module_port(existing_module, existing_port);
1464	    VTR_ASSERT(existing_port_info == new_port_info);
1465	    if (new_port_type !=
1466	        ModuleManager::e_module_port_type::MODULE_OUTPUT_PORT) {
1467	      for (size_t ipin = 0; ipin < new_port_info.pins().size(); ++ipin) {
1468	        /* Create new net */
1469	        ModuleNetId new_net = create_module_net(wrapper_module);
1470	        VTR_ASSERT(valid_module_net_id(wrapper_module, new_net));
1471	        add_module_net_source(wrapper_module, new_net, wrapper_module, 0,
1472	                              new_port, new_port_info.pins()[ipin]);
1473	        add_module_net_sink(wrapper_module, new_net, existing_module, 0,
1474	                            existing_port, existing_port_info.pins()[ipin]);
1475	      }
1476	    } else {
1477	      VTR_ASSERT_SAFE(new_port_type ==
1478	                      ModuleManager::e_module_port_type::MODULE_OUTPUT_PORT);
1479	      for (size_t ipin = 0; ipin < new_port_info.pins().size(); ++ipin) {
1480	        /* Create new net */
1481	        ModuleNetId new_net = create_module_net(wrapper_module);
1482	        VTR_ASSERT(valid_module_net_id(wrapper_module, new_net));
1483	        add_module_net_source(wrapper_module, new_net, existing_module, 0,
1484	                              existing_port, new_port_info.pins()[ipin]);
1485	        add_module_net_sink(wrapper_module, new_net, wrapper_module, 0,
1486	                            new_port, existing_port_info.pins()[ipin]);
1487	      }
1488	    }
1489	  }
1490	
1491	  return wrapper_module;
1492	}
